def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        score = 0.0
        adjustment = 1.0
        penalty = 0.0
        decay = 1.0
        complex_factor = 0.0
        for m in range(1, 15):
            base = np.cos(ratio * m) + np.sin(cap / (m + 1))
            if base < 0.5:
                base = abs(base) * np.exp(-ratio)
            else:
                base *= (1 + 0.05 * m)
            if m % 4 == 0:
                base *= (1 - 0.03 * np.log1p(cap + m))
            elif m % 3 == 0:
                base *= (1 + 0.02 * np.sqrt(item + m))
            if m % 5 == 0 and cap % (m + 2) == 0:
                penalty += np.tanh(base * ratio) * m
            if (cap + m * m) % 11 == 0:
                decay *= 0.95
            else:
                decay *= 1.02
            for n in range(1, 8):
                val = (cap - item * n) / (n + m)
                if val > 0:
                    complex_factor += (np.log1p(val) * np.sin(n * ratio)) / (m + 1)
                else:
                    complex_factor -= (np.abs(val) ** 1.5) / (m + n + 1)
            if ratio > 0.7 and m % 2 == 1:
                adjustment *= (1 + 0.03 * m)
            elif ratio < 0.3 and m % 2 == 0:
                adjustment *= (0.9 - 0.02 * m)
            if cap % (m + 3) == 0:
                penalty += 0.5 * np.cos(m * ratio)
            else:
                penalty -= 0.3 * np.sin(m * ratio)
            score += base * m
        score = score * decay + penalty * 0.5 + complex_factor * 0.7
        score *= adjustment
        if score < 0:
            priorities[i] = -score / (np.sqrt(cap) + 1) * (1 + ratio) * (1 + np.log1p(item))
        else:
            if cap < 2 * item:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
            else:
                priorities[i] = -score / (np.power(cap, 0.6) + 1) * (1 + ratio**2)
        if cap % 2 == 1 and ratio > 0.9:
            priorities[i] *= 1.2
        elif cap % 3 == 0 and ratio < 0.1:
            priorities[i] *= 0.7
        if 0.4 < ratio < 0.6:
            priorities[i] *= 1.1 + 0.05 * np.sin(cap)
    return priorities
